/**
 * String template helpers for generating TypeScript source code.
 */

/** Indent every line of `text` by `level` × 2 spaces. */
export function indent(text: string, level: number): string {
  const pad = '  '.repeat(level)
  return text
    .split('\n')
    .map((line) => (line.trim() === '' ? '' : pad + line))
    .join('\n')
}

/** Wrap `body` in a TypeScript `export interface Name { ... }` block. */
export function tsInterface(name: string, body: string): string {
  return `export interface ${name} {\n${indent(body, 1)}\n}`
}

/** Wrap `body` in a TypeScript `export interface Name { ... }` with Partial fields (all optional). */
export function tsPartialInterface(name: string, body: string): string {
  return `export interface ${name} {\n${indent(body, 1)}\n}`
}

/** Produce a single TypeScript property line, e.g. `name: string`. */
export function tsProperty(name: string, type: string, optional: boolean): string {
  return `${name}${optional ? '?' : ''}: ${type}`
}

/** Wrap `body` in a TypeScript `export class Name { ... }` block. */
export function tsClass(name: string, body: string): string {
  return `export class ${name} {\n${indent(body, 1)}\n}`
}

/** Produce a method signature string. */
export function tsMethod(name: string, params: string, returnType: string, body: string): string {
  return `async ${name}(${params}): Promise<${returnType}> {\n${indent(body, 2)}\n  }`
}

/** Join multiple code blocks with blank lines. */
export function joinBlocks(blocks: string[]): string {
  return blocks.join('\n\n')
}

/**
 * Generate the file header with imports and base client configuration.
 */
export function fileHeader(): string {
  return `// Generated by @prisma/generator-rest-client — do not edit manually.

/**
 * Configuration for the REST API client.
 */
export interface RestClientConfig {
  /** Base URL of the REST API (e.g. "https://api.example.com"). */
  baseUrl: string
  /** Optional headers included in every request. */
  headers?: Record<string, string>
}

type RequestOptions = {
  method: string
  path: string
  body?: unknown
  query?: Record<string, string>
}

async function request<T>(config: RestClientConfig, options: RequestOptions): Promise<T> {
  const url = new URL(options.path, config.baseUrl)

  if (options.query) {
    for (const [key, value] of Object.entries(options.query)) {
      if (value !== undefined) {
        url.searchParams.set(key, value)
      }
    }
  }

  const response = await fetch(url.toString(), {
    method: options.method,
    headers: {
      'Content-Type': 'application/json',
      ...config.headers,
    },
    body: options.body !== undefined ? JSON.stringify(options.body) : undefined,
  })

  if (!response.ok) {
    throw new Error(\`REST client request failed: \${options.method} \${options.path} responded with \${response.status}\`)
  }

  return response.json() as Promise<T>
}`
}

