import type { GeneratorConfig, GeneratorManifest, GeneratorOptions } from '@prisma/generator-helper'

import { generatorHandler } from '@prisma/generator-helper'

import { generate, writeGeneratedClient } from './generator'

const DEFAULT_OUTPUT = './generated/rest-client'

generatorHandler({
  onManifest(_config: GeneratorConfig): GeneratorManifest {
    return {
      prettyName: 'Prisma REST Client',
      defaultOutput: DEFAULT_OUTPUT,
      version: '0.0.0',
    }
  },

  async onGenerate(options: GeneratorOptions): Promise<void> {
    const output = options.generator.output?.value ?? DEFAULT_OUTPUT
    const content = generate(options.dmmf)
    await writeGeneratedClient(output, content)
  },
})

import path from 'node:path'
import fs from 'node:fs/promises'

import type { DMMF } from '@prisma/generator-helper'

import {
  fileHeader,
  indent,
  joinBlocks,
  tsClass,
  tsInterface,
  tsMethod,
  tsProperty,
} from './template'

/**
 * Map a Prisma scalar type to a TypeScript type string.
 */
function mapScalarType(prismaType: string): string {
  switch (prismaType) {
    case 'String':
      return 'string'
    case 'Boolean':
      return 'boolean'
    case 'Int':
    case 'Float':
    case 'Decimal':
      return 'number'
    case 'BigInt':
      return 'bigint'
    case 'DateTime':
      return 'Date | string'
    case 'Json':
    case 'JSON':
      return 'unknown'
    case 'Bytes':
      return 'Buffer'
    default:
      return 'unknown'
  }
}

/**
 * Resolve the TypeScript type for a DMMF field.
 *
 * Scalar fields map to TS primitives. Enum fields use the enum name directly.
 * Object (relation) fields are skipped by the caller, so we return the model
 * name as-is for any remaining cases.
 */
function resolveFieldType(field: DMMF.Field, enumNames: Set<string>): string {
  let tsType: string

  if (field.kind === 'scalar') {
    tsType = mapScalarType(field.type)
  } else if (field.kind === 'enum') {
    tsType = field.type
  } else {
    tsType = field.type
  }

  if (field.isList) {
    tsType = `${tsType}[]`
  }

  return tsType
}

/** Generate the TypeScript interface for a single model. */
function generateModelInterface(model: DMMF.Model, enumNames: Set<string>): string {
  const properties = model.fields
    .filter((field) => field.kind !== 'object')
    .map((field) => {
      const tsType = resolveFieldType(field, enumNames)
      const optional = !field.isRequired && !field.isId
      return tsProperty(field.name, tsType, optional)
    })

  return tsInterface(model.name, properties.join('\n'))
}

/** Generate a "create input" interface — all fields except auto-generated ones. */
function generateCreateInput(model: DMMF.Model, enumNames: Set<string>): string {
  const properties = model.fields
    .filter((field) => field.kind !== 'object')
    .filter((field) => !field.isGenerated && !field.isUpdatedAt && !field.isReadOnly)
    .map((field) => {
      const tsType = resolveFieldType(field, enumNames)
      const optional = !field.isRequired || field.hasDefaultValue || field.isId
      return tsProperty(field.name, tsType, optional)
    })

  return tsInterface(`${model.name}CreateInput`, properties.join('\n'))
}

/** Generate an "update input" interface — all non-relation fields as optional. */
function generateUpdateInput(model: DMMF.Model, enumNames: Set<string>): string {
  const properties = model.fields
    .filter((field) => field.kind !== 'object')
    .filter((field) => !field.isGenerated && !field.isReadOnly)
    .map((field) => {
      const tsType = resolveFieldType(field, enumNames)
      return tsProperty(field.name, tsType, true)
    })

  return tsInterface(`${model.name}UpdateInput`, properties.join('\n'))
}

/** Generate a "where unique" interface — only unique / id fields. */
function generateWhereUniqueInput(model: DMMF.Model, enumNames: Set<string>): string {
  const uniqueFields = model.fields.filter((field) => field.isId || field.isUnique)

  const properties = uniqueFields.map((field) => {
    const tsType = resolveFieldType(field, enumNames)
    return tsProperty(field.name, tsType, !field.isId)
  })

  return tsInterface(`${model.name}WhereUniqueInput`, properties.join('\n'))
}

/** Lower-case the first character of a string. */
function lowerFirst(str: string): string {
  return str.charAt(0).toLowerCase() + str.slice(1)
}

/** Generate the CRUD delegate class for a single model. */
function generateModelDelegate(model: DMMF.Model): string {
  const modelName = model.name
  const resourcePath = `/${lowerFirst(modelName)}`

  const methods = [
    tsMethod(
      'findMany',
      `query?: Record<string, string>`,
      `${modelName}[]`,
      `return request<${modelName}[]>(this.#config, {\n  method: 'GET',\n  path: '${resourcePath}',\n  query,\n})`,
    ),
    tsMethod(
      'findUnique',
      `where: ${modelName}WhereUniqueInput`,
      `${modelName} | null`,
      `const id = ${generateIdAccessExpression(model)}\nreturn request<${modelName} | null>(this.#config, {\n  method: 'GET',\n  path: \`${resourcePath}/\${id}\`,\n})`,
    ),
    tsMethod(
      'create',
      `data: ${modelName}CreateInput`,
      `${modelName}`,
      `return request<${modelName}>(this.#config, {\n  method: 'POST',\n  path: '${resourcePath}',\n  body: data,\n})`,
    ),
    tsMethod(
      'update',
      `where: ${modelName}WhereUniqueInput, data: ${modelName}UpdateInput`,
      `${modelName}`,
      `const id = ${generateIdAccessExpression(model)}\nreturn request<${modelName}>(this.#config, {\n  method: 'PATCH',\n  path: \`${resourcePath}/\${id}\`,\n  body: data,\n})`,
    ),
    tsMethod(
      'delete',
      `where: ${modelName}WhereUniqueInput`,
      `${modelName}`,
      `const id = ${generateIdAccessExpression(model)}\nreturn request<${modelName}>(this.#config, {\n  method: 'DELETE',\n  path: \`${resourcePath}/\${id}\`,\n})`,
    ),
  ]

  const body = `#config: RestClientConfig\n\nconstructor(config: RestClientConfig) {\n  this.#config = config\n}\n\n${methods.join('\n\n')}`

  return tsClass(`${modelName}Delegate`, body)
}

/**
 * Build an expression that extracts the primary identifier value from a
 * `WhereUniqueInput` object.  Falls back to the first unique field if no
 * `@id` field is defined.
 */
function generateIdAccessExpression(model: DMMF.Model): string {
  const idField = model.fields.find((f) => f.isId) ?? model.fields.find((f) => f.isUnique)
  const fieldName = idField?.name ?? 'id'
  return `where.${fieldName}`
}

/** Generate enum string union types. */
function generateEnum(enumDef: DMMF.DatamodelEnum): string {
  const values = enumDef.values.map((v) => `'${v.name}'`).join(' | ')
  return `export type ${enumDef.name} = ${values}`
}

/** Generate the top-level `RestClient` class that exposes all model delegates. */
function generateRestClient(models: readonly DMMF.Model[]): string {
  const fields = models.map((m) => {
    const delegateName = `${m.name}Delegate`
    const fieldName = lowerFirst(m.name)
    return `${fieldName}: ${delegateName}`
  })

  const assignments = models.map((m) => {
    const delegateName = `${m.name}Delegate`
    const fieldName = lowerFirst(m.name)
    return `this.${fieldName} = new ${delegateName}(config)`
  })

  const body = `${fields.join('\n')}\n\nconstructor(config: RestClientConfig) {\n${indent(assignments.join('\n'), 1)}\n}`

  return tsClass('RestClient', body)
}

/**
 * Main generation entry point. Takes the DMMF document and produces
 * the full `rest-client.ts` source string.
 */
export function generate(dmmf: DMMF.Document): string {
  const models = dmmf.datamodel.models
  const enums = dmmf.datamodel.enums
  const enumNames = new Set(enums.map((e) => e.name))

  const blocks: string[] = [fileHeader()]

  // Enums as string union types
  for (const enumDef of enums) {
    blocks.push(generateEnum(enumDef))
  }

  // Per-model types and delegate classes
  for (const model of models) {
    blocks.push(generateModelInterface(model, enumNames))
    blocks.push(generateCreateInput(model, enumNames))
    blocks.push(generateUpdateInput(model, enumNames))
    blocks.push(generateWhereUniqueInput(model, enumNames))
    blocks.push(generateModelDelegate(model))
  }

  // Top-level client
  blocks.push(generateRestClient(models))

  return joinBlocks(blocks) + '\n'
}

/**
 * Write the generated REST client to disk at the specified output directory.
 */
export async function writeGeneratedClient(outputDir: string, content: string): Promise<void> {
  await fs.mkdir(outputDir, { recursive: true })
  await fs.writeFile(path.join(outputDir, 'rest-client.ts'), content, 'utf-8')
}

