import type * as esbuild from 'esbuild'
import path from 'path'

type TsConfig = {
  compilerOptions?: {
    paths?: Record<string, string[]>
  }
  extends?: string
}

/**
 * Recursive function to resolve the paths config from a tsconfig.json, whether
 * it is in the config directly or via an inherited config (via "extends").
 * @param options
 * @param cwd
 * @returns
 */
function resolvePathsConfig(options: TsConfig, cwd: string) {
  if (options?.compilerOptions?.paths) {
    const paths = Object.entries(options.compilerOptions.paths)

    const resolvedPaths = paths.map(([key, paths]) => {
      return [key, paths.map((v) => path.resolve(cwd, v))] as const
    })

    return Object.fromEntries(resolvedPaths)
  }

  if (options.extends) {
    const extendsPath = path.resolve(cwd, options.extends)
    const extendsDir = path.dirname(extendsPath)
    const extendsConfig = require(extendsPath)

    return resolvePathsConfig(extendsConfig, extendsDir)
  }

  return []
}

/**
 * Forces `esbuild` to always use the TS compiler paths, even when we are
 * bundling a local dependency of a local dependency, ensuring maximum
 * tree-shaking. Note: `esbuild` has some support for this, though it is limited
 * in the amount of dependency nesting it supports.
 */
export const resolvePathsPlugin: esbuild.Plugin = {
  name: 'resolvePathsPlugin',
  setup(build) {
    const parentTsConfig = require(`${process.cwd()}/${build.initialOptions.tsconfig}`)
    const resolvedTsPaths = resolvePathsConfig(parentTsConfig, process.cwd())
    const packagesRegex = new RegExp(`^(${Object.keys(resolvedTsPaths).join('|')})$`)

    build.onResolve({ filter: packagesRegex }, (args) => {
      if (build.initialOptions.external?.includes(args.path)) {
        return { path: args.path, external: true }
      }

      return { path: `${resolvedTsPaths[args.path][0]}/index.ts` }
    })
  },
}

import path from 'node:path'

import { BuildOptions } from './build'

type AdapterEntry = {
  entry: string
  outfile: string
}

export function createAdapterConfig(entries: AdapterEntry[]): BuildOptions[] {
  return entries.flatMap(({ entry, outfile }) => {
    const baseName = path.basename(outfile)

    return [
      {
        name: `${baseName}-cjs`,
        format: 'cjs' as const,
        bundle: true,
        entryPoints: [entry],
        outfile,
        outExtension: { '.js': '.js' },
        emitTypes: true,
      },
      {
        name: `${baseName}-esm`,
        format: 'esm' as const,
        bundle: true,
        entryPoints: [entry],
        outfile,
        outExtension: { '.js': '.mjs' },
        emitTypes: true,
      },
    ]
  })
}

export const adapterConfig = createAdapterConfig([{ entry: 'src/index.ts', outfile: 'dist/index' }])

export const unbundledConfig: BuildOptions[] = [
  {
    name: 'cjs',
    format: 'cjs',
    entryPoints: ['src/**/*.ts'],
    outdir: 'dist',
    outExtension: { '.js': '.js' },
    emitTypes: true,
  },
  {
    name: 'esm',
    format: 'esm',
    entryPoints: ['src/**/*.ts'],
    outdir: 'dist',
    outExtension: { '.js': '.mjs' },
    emitTypes: true,
  },
]

/**
 * We only want to trigger the glob search once we are ready, and that is when
 * the previous build has finished. We get the build options from the deferred.
 */
function computeOptions(options: () => BuildOptions) {
  return options()
}

/**
 * Extensions are not automatically by esbuild set for `options.outfile`. We
 * look at the set `options.outExtension` and we add that to `options.outfile`.
 */
function addExtensionFormat(options: BuildOptions) {
  if (options.outfile && options.outExtension) {
    const ext = options.outExtension['.js']

    options.outfile = `${options.outfile}${ext}`
  }

  return options
}

/**
 * If we don't have `options.outfile`, we default `options.outdir`
 */
function addDefaultOutDir(options: BuildOptions) {
  if (options.outfile === undefined) {
    options.outdir = getOutDir(options)
  }

  return options
}

/**
 * Execute esbuild with all the configurations we pass
 */
async function executeEsBuild(options: BuildOptions) {
  if (process.env.WATCH === 'true') {
    const context = await esbuild.context(omit(options, ['name', 'emitTypes', 'emitMetafile']) as any)

    watch(context, options)
  }

  const build = await esbuild.build(omit(options, ['name', 'emitTypes', 'emitMetafile']) as any)
  const outdir = options.outdir ?? (options.outfile ? path.dirname(options.outfile) : undefined)

  if (build.metafile && options.emitMetafile) {
    const metafilePath = `${outdir}/${options.name}.meta.json`
    writeFileSync(metafilePath, JSON.stringify(build.metafile))
  }

  return [options, build] as const
}

/**
 * Execution pipeline that applies a set of actions
 * @param options
 */
export async function build(options: BuildOptions[]) {
  return transduce.async(
    createBuildOptions(options),
    pipe.async(computeOptions, logStartBuild, addExtensionFormat, addDefaultOutDir, executeEsBuild),
  )
}

/**
 * Prints a message every time a new bundle is built
 */
function logStartBuild(options: BuildOptions): BuildOptions {
  console.log(`Building ${options.name} as ${options.format ?? 'cjs'}...`)
  return options
}

/**
 * Executes the build and rebuilds what is necessary
 * @param builds
 */
const watch = (context: BuildContext, options: BuildOptions) => {
  if (process.env.WATCH !== 'true') return context

function getProjectExternals(options: BuildOptions) {
  const pkg = require(`${process.cwd()}/package.json`)
  const peerDeps = Object.keys(pkg.peerDependencies ?? {})
  const regDeps = Object.keys(pkg.dependencies ?? {})

  // when bundling, only the devDeps will be bundled
  if (!process.env.IGNORE_EXTERNALS && options.bundle === true) {
    return [...new Set([...peerDeps, ...regDeps])]
  }

  // otherwise, all the dependencies will be bundled
  return []
}

import { Extractor, ExtractorConfig } from '@microsoft/api-extractor'
import type * as esbuild from 'esbuild'
import fs from 'fs-extra'
import path from 'path'

import { run } from '../run'

/**
 * Bundle all type definitions by using the API Extractor from RushStack
 * @param filename the source d.ts to bundle
 * @param outfile the output bundled file
 */
function bundleTypeDefinitions(filename: string, outfile: string, externals: string[]) {
  const { dependencies, peerDependencies, devDependencies } = require(`${process.cwd()}/package.json`)

  // get the list of bundled and non bundled as well as their eventual type dependencies
  const dependenciesKeys = Object.keys(dependencies ?? {}).flatMap((p) => [p, getTypeDependencyPackageName(p)])
  const peerDependenciesKeys = Object.keys(peerDependencies ?? {}).flatMap((p) => [p, getTypeDependencyPackageName(p)])
  const devDependenciesKeys = Object.keys(devDependencies ?? {}).flatMap((p) => [p, getTypeDependencyPackageName(p)])

  const includeDeps = devDependenciesKeys
  const excludeDeps = [...dependenciesKeys, ...peerDependenciesKeys, ...externals]
  const bundledPackages = includeDeps.filter((dep) => !excludeDeps.includes(dep))

  // we give the config in its raw form instead of a file
  const extractorConfig = ExtractorConfig.prepare({
    configObject: {
      projectFolder: process.cwd(),
      mainEntryPointFilePath: filename,
      bundledPackages,
      compiler: {
        tsconfigFilePath: path.join(process.cwd(), 'tsconfig.build.json'),
        overrideTsconfig: {
          compilerOptions: {
            paths: {}, // bug with api extract + paths
          },
        },
      },
      dtsRollup: {
        enabled: true,
        untrimmedFilePath: path.join(process.cwd(), `${outfile}.d.ts`),
      },
      tsdocMetadata: {
        enabled: false,
      },
    },
    packageJsonFullPath: path.join(process.cwd(), 'package.json'),
    configObjectFullPath: undefined,
  })

  // here we trigger the "command line" interface equivalent
  const extractorResult = Extractor.invoke(extractorConfig, {
    showVerboseMessages: true,
    localBuild: true,
  })

  // we exit the process immediately if there were errors
  if (extractorResult.succeeded === false) {
    console.error(`API Extractor completed with errors`)
    process.exit(1)
  }
}

/**
 * Triggers the TypeScript compiler and the type bundler.
 */
export const tscPlugin: (emitTypes?: boolean) => esbuild.Plugin = (emitTypes?: boolean) => ({
  name: 'tscPlugin',
  setup(build) {
    const options = build.initialOptions

    if (emitTypes === false) return // build has opted out of emitting types

    build.onStart(async () => {
      // we only call tsc if not in watch mode or in dev mode (they skip types)
      if (process.env.WATCH !== 'true' && process.env.DEV !== 'true') {
        // --paths null basically prevents typescript from using paths from the
        // tsconfig.json that is passed from the esbuild config. We need to do
        // this because TS would include types from the paths into this build.
        // but our paths, in our specific case only represent separate packages.
        await run(`tsc --project ${options.tsconfig} --paths null`)
      }

      // we bundle types if we also bundle the entry point and it is a ts file
      if (options.bundle && options.outfile && options.entryPoints?.[0].endsWith('.ts')) {
        const tsconfig = require(`${process.cwd()}/${options.tsconfig}`) // tsconfig
        const typeOutDir = tsconfig?.compilerOptions?.outDir ?? '.' // type out dir
        const entryPoint = options.entryPoints?.[0].replace(/\.ts$/, '')
        const bundlePath = options.outfile.replace(/\.m?js$/, '')
        const typeOutPath = [
          `${process.cwd()}/${typeOutDir}/${entryPoint}.d.ts`,
          `${process.cwd()}/${typeOutDir}/${entryPoint.replace(/^src\//, '')}.d.ts`,
        ].filter(fs.existsSync)[0]

        const ext = options.format === 'esm' ? 'd.mts' : 'd.ts'
        if (process.env.WATCH !== 'true' && process.env.DEV !== 'true') {
          // we get the types generated by tsc and bundle them near the output
          bundleTypeDefinitions(typeOutPath, bundlePath, options.external ?? [])

          const dtsContents = await fs.readFile(`${bundlePath}.d.ts`, 'utf-8')
          await fs.outputFile(`${bundlePath}.${ext}`, dtsContents)
        } else {
          // in watch mode, it wouldn't be viable to bundle the types every time
          // we haven't built any types with tsc at this stage, but we want types
          // we link the types locally by re-exporting them from the entry point
          await fs.outputFile(`${bundlePath}.${ext}`, `export * from '${process.cwd()}/${entryPoint}'`)
        }
      }
    })
  },
})

/**
 * Automatically get the type dependency package name, following the
 * DefinitelyTyped naming conventions.
 * @param npmPackage
 * @returns
 */
function getTypeDependencyPackageName(npmPackage: string) {
  if (npmPackage.startsWith('@')) {
    const [scope, name] = npmPackage.split('/')

    return `@types/${scope.slice(1)}__${name}`
  } else {
    return `@types/${npmPackage}`
  }
}

